// Structured output: AI returns this as JSON:
public record DisputeClassification(
    String category,       // FRAUD | MERCHANT_ERROR | CUSTOMER_ERROR
    int confidencePct,     // 0-100: how confident the AI is
    String explanation,    // brief reason for the classification
    boolean requiresHuman  // should a human agent review?
) {}

@Service
public class StructuredAiService {
    private final ChatClient chatClient;
    private final BeanOutputConverter<DisputeClassification> converter;

    public StructuredAiService(ChatClient.Builder builder) {
        this.converter = new BeanOutputConverter<>(DisputeClassification.class);
        this.chatClient = builder
            .defaultSystem("""
                You are a payment dispute classifier.
                Always respond with valid JSON matching the requested schema.
                Be precise and concise in your explanation.
                """)
            .build();
    }

    public DisputeClassification classify(String disputeDetails) {
        String format = converter.getFormat(); // JSON schema instruction for AI

        String response = chatClient.prompt()
            .user(u -> u.text("""
                Classify this payment dispute:
                {details}

                {format}
                """)
                .param("details", disputeDetails)
                .param("format", format))
            .call()
            .content();

        return converter.convert(response); // JSON → DisputeClassification
    }
}

@SpringBootTest
class StructuredAiTest {
    @Test void converter_schema_documented() {
        // BeanOutputConverter generates JSON schema for the AI:
        var conv = new BeanOutputConverter<>(DisputeClassification.class);
        String schema = conv.getFormat();
        assertTrue(schema.contains("category"), "Schema should include field names");
        assertTrue(schema.contains("confidencePct"));
        System.out.println("Converter schema tells AI exactly what JSON to produce");
    }
}

