@Service
class ConversationStore {
    private final Map<String, List<Message>> sessions = new HashMap<>();

    void addMessage(String sessionId, Message msg) {
        sessions.computeIfAbsent(sessionId, k -> new ArrayList<>()).add(msg);
    }

    List<Message> getHistory(String sessionId) {
        return sessions.getOrDefault(sessionId, List.of());
    }

    int getMessageCount(String sessionId) {
        return sessions.getOrDefault(sessionId, List.of()).size();
    }

    void clearSession(String sessionId) {
        sessions.remove(sessionId);
    }
}

@Service
class MultiTurnBankAiService {
    private final ChatClient client;
    private final ConversationStore store;

    MultiTurnBankAiService(ChatClient.Builder b, ConversationStore s) {
        client = b.defaultSystem("""
            You are an HDFC Bank assistant.
            You remember the conversation context.
            Be helpful and concise.
            """).build();
        store = s;
    }

    public String chat(String sessionId, String userMessage) {
        // Add current user message to history:
        store.addMessage(sessionId, new UserMessage(userMessage));

        // Build prompt with full conversation history:
        var call = client.prompt();
        List<Message> history = store.getHistory(sessionId);
        // In Spring AI 1.0: use .messages(history) to include history
        // Simplified here: just send user message (real impl includes history)
        String response = call.user(userMessage).call().content();

        // Store AI response:
        store.addMessage(sessionId, new AssistantMessage(response));
        return response;
    }
}

@SpringBootTest
class MultiTurnTest {
    @Autowired ConversationStore store;

    @Test void firstMessage_startsSession() {
        store.addMessage("S1", new UserMessage("What is my loan status?"));
        assertEquals(1, store.getMessageCount("S1"));
    }
    @Test void followUp_historyGrows() {
        store.addMessage("S2", new UserMessage("What is my EMI?"));
        store.addMessage("S2", new AssistantMessage("Your EMI is ₹15,000."));
        store.addMessage("S2", new UserMessage("When is the next due date?"));
        assertEquals(3, store.getMessageCount("S2"));
        // The 3rd message can reference 'the EMI' from message 2
    }
}

