import org.springframework.stereotype.*;
import io.github.bucket4j.*;
import org.springframework.boot.test.context.SpringBootTest;
import org.springframework.beans.factory.annotation.Autowired;
import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.*;
import java.time.Duration;
import java.util.*;
import java.util.concurrent.ConcurrentHashMap;

class AiRateLimitExceededException extends RuntimeException {
    AiRateLimitExceededException(String m) { super(m); }
}

@Service
class AiRateLimiter {
    // Per-merchant buckets: 10 AI calls per minute
    private final Map<String, Bucket> buckets = new ConcurrentHashMap<>();

    private Bucket getBucket(String merchantId) {
        return buckets.computeIfAbsent(merchantId, k ->
            Bucket.builder()
                .addLimit(Bandwidth.classic(10, Refill.greedy(10, Duration.ofMinutes(1))))
                .build());
    }

    public void checkAndConsume(String merchantId) {
        Bucket bucket = getBucket(merchantId);
        if (!bucket.tryConsume(1)) {
            long waitSeconds = bucket.estimateAbilityToConsume(1).getNanosToWaitForRefill() / 1_000_000_000;
            throw new AiRateLimitExceededException(
                "AI rate limit exceeded for merchant " + merchantId +
                ". Retry in " + waitSeconds + "s. (Max 10 AI calls/minute)");
        }
    }

    public long availableTokens(String merchantId) {
        return getBucket(merchantId).getAvailableTokens();
    }
}

@Service
class RateLimitedAiService {
    private final AiRateLimiter limiter;
    RateLimitedAiService(AiRateLimiter l) { limiter = l; }

    public String ask(String merchantId, String question) {
        limiter.checkAndConsume(merchantId); // throws if rate limit exceeded
        // AI call would go here:
        return "[AI Response for: " + question + "]";
    }
}

@SpringBootTest
class AiRateLimitTest {
    @Autowired AiRateLimiter limiter;
    @Autowired RateLimitedAiService svc;

    @Test void withinLimit_passes() {
        String merchant = "MRC-RL-" + System.nanoTime();
        String result = svc.ask(merchant, "What is my balance?");
        assertNotNull(result);
        assertEquals(9, limiter.availableTokens(merchant)); // 1 consumed
    }
    @Test void exceededLimit_throws() {
        String merchant = "MRC-RL-EXHAUST-" + System.nanoTime();
        // Exhaust all 10 tokens:
        for (int i = 0; i < 10; i++) limiter.checkAndConsume(merchant);
        // 11th call should throw:
        assertThrows(AiRateLimitExceededException.class,
            () -> svc.ask(merchant, "One more question"));
    }
}

