@Component
class HdfcAccountTools {
    private final Map<String,String> balances=Map.of("ACC-1","₹50,000","ACC-2","₹1,23,456");
    private final Map<String,String> txns=Map.of("ACC-1","Swiggy ₹350, Salary ₹60000","ACC-2","Flipkart ₹4500, EMI ₹15000");
    @Tool(description="Get account balance") public String getBalance(String id){return balances.getOrDefault(id,"Not found");}
    @Tool(description="Get last transactions") public String getTransactions(String id){return txns.getOrDefault(id,"Not found");}
}

@Service
class HdfcSupport {
    private final ChatClient client;
    private final Map<String,List<Message>> history=new ConcurrentHashMap<>();
    private final Map<String,Bucket> limits=new ConcurrentHashMap<>();

    HdfcSupport(ChatClient.Builder b, HdfcAccountTools tools) {
        client=b.defaultSystem("""
            You are HDFC Bank's AI assistant.
            Use tools to fetch real account data. Be concise and professional.
            """).defaultTools(tools).build();
    }

    private Bucket getBucket(String customerId) {
        return limits.computeIfAbsent(customerId, k ->
            Bucket.builder().addLimit(Bandwidth.classic(20,Refill.greedy(20,Duration.ofMinutes(1)))).build());
    }

    public String answer(String sessionId, String customerId, String question) {
        if(!getBucket(customerId).tryConsume(1)) throw new RuntimeException("Rate limit: try again in 1 minute");
        history.computeIfAbsent(sessionId, k->new ArrayList<>()).add(new UserMessage(question));
        String response = client.prompt().user(question).call().content();
        history.get(sessionId).add(new AssistantMessage(response));
        return response;
    }
    int historySize(String sessionId){return history.getOrDefault(sessionId,List.of()).size();}
    long availableTokens(String customerId){return getBucket(customerId).getAvailableTokens();}
}

@SpringBootTest
class HdfcSupportTest {
    @Autowired HdfcAccountTools tools;
    @Autowired HdfcSupport support;
    @Test void tool_balance(){assertEquals("₹50,000",tools.getBalance("ACC-1"));}
    @Test void rateLimit_tracked(){
        support.answer("S1","C1","Hello");
        assertEquals(19,support.availableTokens("C1")); // 1 consumed
    }
    @Test void history_accumulates(){
        support.answer("S2","C2","Q1");
        support.answer("S2","C2","Q2");
        assertEquals(4,support.historySize("S2")); // 2 user + 2 assistant
    }
}

