        Pattern.compile("ignore\\s+(previous|above|all|prior)", Pattern.CASE_INSENSITIVE),
        Pattern.compile("system\\s*:", Pattern.CASE_INSENSITIVE),
        Pattern.compile("you\\s+are\\s+now", Pattern.CASE_INSENSITIVE),
        Pattern.compile("forget\\s+(everything|all|instructions)", Pattern.CASE_INSENSITIVE),
        Pattern.compile("new\\s+instructions", Pattern.CASE_INSENSITIVE),
        Pattern.compile("disregard\\s+(your|all|previous)", Pattern.CASE_INSENSITIVE),
        Pattern.compile("\\[\\[.{0,50}\\]\\]") // [[system override]] style
    );

    public record SanitizationResult(boolean isClean, String sanitizedInput, String detectedPattern) {}

    public SanitizationResult sanitize(String userInput) {
        if (userInput == null || userInput.isBlank()) {
            return new SanitizationResult(true, "", null);
        }
        for (Pattern p : INJECTION_PATTERNS) {
            Matcher m = p.matcher(userInput);
            if (m.find()) {
                return new SanitizationResult(false, null, p.pattern());
            }
        }
        // Clean: truncate to max length (prevent token bomb):
        String safe = userInput.substring(0, Math.min(userInput.length(), 2000));
        return new SanitizationResult(true, safe, null);
    }

    public boolean isInjectionAttempt(String input) {
        return !sanitize(input).isClean();
    }
}

@SpringBootTest
class PromptInjectionGuardTest {
    @Autowired PromptInjectionGuard guard;

    @Test void cleanInput_passes() {
